    fn git_fringe_refresh_due(&self, now: Instant, typing_active: bool) -> bool {
        !typing_active
            && self.git_fringe_dirty
            && self
                .git_fringe_last_edit_at
                .map(|last| now.duration_since(last) >= GIT_FRINGE_REFRESH_DEBOUNCE)
                .unwrap_or(true)
    }

