fn sync_active_buffer(runtime: &mut EditorRuntime) -> Result<(), String> {
    let Some((pane_id, buffer_id, buffer_name, buffer_kind)) = active_runtime_buffer(runtime)?
    else {
        return Ok(());
    };
    let is_git_commit = buffer_is_git_commit(&buffer_kind);
    let is_git_status = buffer_is_git_status(&buffer_kind);
    let is_directory = buffer_is_directory(&buffer_kind);
    let is_terminal = buffer_is_terminal(&buffer_kind);

    let (previous_pane, previous_buffer) = {
        let ui = shell_ui(runtime)?;
        (ui.active_pane_id(), ui.active_buffer_id())
    };
    let should_enter_insert = {
        let user_library = shell_user_library(runtime);
        let ui = shell_ui_mut(runtime)?;
        if previous_pane != Some(pane_id) {
            ui.focus_pane(pane_id);
        } else if previous_buffer != Some(buffer_id) {
            ui.close_autocomplete();
            ui.close_hover();
        }
        let has_input = ui
            .ensure_buffer(buffer_id, &buffer_name, buffer_kind, &*user_library)
            .has_input_field();
        ui.focus_buffer_in_active_pane(buffer_id);
        if !is_git_commit {
            ui.pending_ctrl_c = None;
        }
        if !is_git_status {
            ui.pending_git_prefix = None;
        }
        if !is_directory {
            ui.pending_directory_prefix = None;
        }
        previous_buffer != Some(buffer_id) && has_input
    };
    let terminal_created = if is_terminal {
        ensure_terminal_session(runtime, buffer_id)?
    } else {
        false
    };
    if should_enter_insert || terminal_created {
        shell_ui_mut(runtime)?.enter_insert_mode();
    }
    if previous_buffer != Some(buffer_id) {
        let workspace_id = runtime
            .model()
            .active_workspace_id()
            .map_err(|error| error.to_string())?;
        let window_id = active_window_id(runtime)?;
        runtime
            .emit_hook(
                builtins::BUFFER_SWITCH,
                HookEvent::new()
                    .with_window(window_id)
                    .with_workspace(workspace_id)
                    .with_pane(pane_id)
                    .with_buffer(buffer_id),
            )
            .map_err(|error| error.to_string())?;
    }
    Ok(())
}

fn active_runtime_surface(runtime: &EditorRuntime) -> Result<Option<(PaneId, BufferId)>, String> {
    Ok(active_runtime_buffer(runtime)?.map(|(pane_id, buffer_id, _, _)| (pane_id, buffer_id)))
}

fn ensure_shell_buffer(runtime: &mut EditorRuntime, buffer_id: BufferId) -> Result<(), String> {
    let (buffer_name, buffer_kind) = {
        let workspace_id = runtime
            .model()
            .active_workspace_id()
            .map_err(|error| error.to_string())?;
        let workspace = runtime
            .model()
            .workspace(workspace_id)
            .map_err(|error| error.to_string())?;
        let buffer = workspace
            .buffer(buffer_id)
            .ok_or_else(|| format!("buffer `{buffer_id}` is missing"))?;
        (buffer.name().to_owned(), buffer.kind().clone())
    };
    let user_library = shell_user_library(runtime);
    shell_ui_mut(runtime)?.ensure_popup_buffer(
        buffer_id,
        &buffer_name,
        buffer_kind,
        &*user_library,
    );
    Ok(())
}

fn refresh_git_status_if_active(runtime: &mut EditorRuntime) -> Result<(), String> {
    let buffer_id = active_shell_buffer_id(runtime)?;
    if !buffer_is_git_status(&shell_buffer(runtime, buffer_id)?.kind) {
        return Ok(());
    }
    refresh_git_status_buffer(runtime, buffer_id)
}

fn refresh_git_status_buffers(runtime: &mut EditorRuntime) -> Result<(), String> {
    let buffer_ids = {
        let ui = shell_ui(runtime)?;
        ui.buffers
            .iter()
            .filter(|buffer| buffer_is_git_status(&buffer.kind))
            .map(ShellBuffer::id)
            .collect::<Vec<_>>()
    };
    for buffer_id in buffer_ids {
        let _ = refresh_git_status_buffer(runtime, buffer_id);
    }
    Ok(())
}

fn refresh_git_status_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    let root = match git_root(runtime) {
        Ok(root) => root,
        Err(error) => {
            set_git_status_error(runtime, buffer_id, &error)?;
            return Err(error);
        }
    };
    let snapshot = match git_status_snapshot(runtime, &root) {
        Ok(snapshot) => snapshot,
        Err(error) => {
            set_git_status_error(runtime, buffer_id, &error)?;
            return Err(error);
        }
    };
    apply_git_status_snapshot(runtime, buffer_id, snapshot)
}

fn set_git_status_error(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    message: &str,
) -> Result<(), String> {
    record_runtime_error(runtime, "git.status", message.to_owned());
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    buffer.replace_with_lines(vec![
        "Git status unavailable.".to_owned(),
        message.to_owned(),
    ]);
    Ok(())
}

fn apply_git_status_snapshot(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    snapshot: GitStatusSnapshot,
) -> Result<(), String> {
    let user_library = shell_user_library(runtime);
    let sections = user_library.git_status_sections(&snapshot);
    let collapsed = shell_buffer(runtime, buffer_id)?
        .section_state()
        .map(|state| state.collapsed.clone())
        .unwrap_or_default();
    let lines = sections.render_lines(&collapsed);
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    {
        let state = buffer.ensure_section_state();
        state.collapsed = collapsed;
    }
    buffer.set_git_snapshot(snapshot);
    buffer.set_section_lines(lines);
    Ok(())
}

fn open_git_status_popup(runtime: &mut EditorRuntime) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let buffer_id = runtime
        .model_mut()
        .create_popup_buffer(
            workspace_id,
            "*git-status*",
            BufferKind::Plugin(GIT_STATUS_KIND.to_owned()),
            None,
        )
        .map_err(|error| error.to_string())?;
    runtime
        .model_mut()
        .open_popup(workspace_id, "Git Status", vec![buffer_id], buffer_id)
        .map_err(|error| error.to_string())?;
    {
        let user_library = shell_user_library(runtime);
        let ui = shell_ui_mut(runtime)?;
        ui.ensure_popup_buffer(
            buffer_id,
            "*git-status*",
            BufferKind::Plugin(GIT_STATUS_KIND.to_owned()),
            &*user_library,
        );
        ui.set_popup_buffer(buffer_id);
    }
    shell_ui_mut(runtime)?.set_popup_focus(true);
    refresh_git_status_buffer(runtime, buffer_id)
}

fn find_shell_buffer_by_kind(ui: &ShellUiState, kind: &str) -> Option<BufferId> {
    ui.buffers.iter().find_map(|buffer| {
        if matches!(&buffer.kind, BufferKind::Plugin(plugin_kind) if plugin_kind == kind) {
            Some(buffer.id())
        } else {
            None
        }
    })
}

fn find_oil_buffer(ui: &ShellUiState) -> Option<BufferId> {
    ui.buffers.iter().find_map(|buffer| {
        if matches!(&buffer.kind, BufferKind::Directory) && buffer.display_name() == OIL_BUFFER_NAME
        {
            Some(buffer.id())
        } else {
            None
        }
    })
}

fn active_shell_buffer_path(runtime: &EditorRuntime) -> Result<Option<PathBuf>, String> {
    let buffer_id = active_shell_buffer_id(runtime)?;
    Ok(shell_buffer(runtime, buffer_id)?
        .path()
        .map(Path::to_path_buf))
}

fn active_directory_root(runtime: &EditorRuntime) -> Result<Option<PathBuf>, String> {
    let buffer_id = active_shell_buffer_id(runtime)?;
    let buffer = shell_buffer(runtime, buffer_id)?;
    Ok(buffer.directory_state().map(|state| state.root.clone()))
}

fn oil_workspace_root(runtime: &EditorRuntime) -> Result<PathBuf, String> {
    if let Some(root) = active_workspace_root(runtime)? {
        return Ok(root);
    }
    env::current_dir().map_err(|error| format!("oil requires a workspace root: {error}"))
}

fn oil_default_root(runtime: &EditorRuntime) -> Result<PathBuf, String> {
    if let Some(root) = active_directory_root(runtime)? {
        return Ok(root);
    }
    if let Some(path) = active_shell_buffer_path(runtime)?
        && let Some(parent) = path.parent()
    {
        return Ok(parent.to_path_buf());
    }
    oil_workspace_root(runtime)
}

fn oil_parent_root(runtime: &EditorRuntime) -> Result<PathBuf, String> {
    if let Some(root) = active_directory_root(runtime)? {
        return Ok(root.parent().unwrap_or(root.as_path()).to_path_buf());
    }
    let root = oil_default_root(runtime)?;
    Ok(root.parent().unwrap_or(root.as_path()).to_path_buf())
}

fn open_oil_directory(runtime: &mut EditorRuntime, root: PathBuf) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let existing = shell_ui(runtime).ok().and_then(find_oil_buffer);
    let buffer_id = if let Some(existing) = existing {
        runtime
            .model_mut()
            .focus_buffer(workspace_id, existing)
            .map_err(|error| error.to_string())?;
        existing
    } else {
        runtime
            .model_mut()
            .create_buffer(workspace_id, OIL_BUFFER_NAME, BufferKind::Directory, None)
            .map_err(|error| error.to_string())?
    };
    {
        let user_library = shell_user_library(runtime);
        let ui = shell_ui_mut(runtime)?;
        ui.ensure_buffer(
            buffer_id,
            OIL_BUFFER_NAME,
            BufferKind::Directory,
            &*user_library,
        );
        ui.focus_buffer_in_active_pane(buffer_id);
        ui.enter_normal_mode();
    }
    set_directory_root(runtime, buffer_id, root)?;
    Ok(())
}

fn ensure_directory_buffer(runtime: &mut EditorRuntime) -> Result<(), String> {
    let buffer_id = active_shell_buffer_id(runtime)?;
    let buffer = shell_buffer(runtime, buffer_id)?;
    if !buffer_is_directory(&buffer.kind) || buffer.directory_state().is_some() {
        return Ok(());
    }
    let root = oil_default_root(runtime)?;
    set_directory_root(runtime, buffer_id, root)
}

fn refresh_directory_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    let (root, show_hidden, sort_mode, trash_enabled) = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        let Some(state) = buffer.directory_state() else {
            let root = oil_default_root(runtime)?;
            return set_directory_root(runtime, buffer_id, root);
        };
        (
            state.root.clone(),
            state.show_hidden,
            state.sort_mode,
            state.trash_enabled,
        )
    };
    let entries = match DirectoryBuffer::read(&root) {
        Ok(buffer) => buffer.entries().to_vec(),
        Err(error) => {
            let message = format!("failed to read `{}`: {error}", root.display());
            set_directory_error(runtime, buffer_id, &message)?;
            return Err(message);
        }
    };
    let defaults = shell_user_library(runtime).oil_defaults();
    let mut state = DirectoryViewState::new(root, entries, defaults);
    state.show_hidden = show_hidden;
    state.sort_mode = sort_mode;
    state.trash_enabled = trash_enabled;
    apply_directory_state(runtime, buffer_id, state)
}

fn set_directory_root(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    root: PathBuf,
) -> Result<(), String> {
    let defaults = shell_user_library(runtime).oil_defaults();
    let (show_hidden, sort_mode, trash_enabled, previous_root) = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        let state = buffer.directory_state();
        (
            state
                .map(|state| state.show_hidden)
                .unwrap_or(defaults.show_hidden),
            state
                .map(|state| state.sort_mode)
                .unwrap_or(defaults.sort_mode),
            state
                .map(|state| state.trash_enabled)
                .unwrap_or(defaults.trash_enabled),
            state.map(|state| state.root.clone()),
        )
    };
    let root_for_compare = root.clone();
    let entries = match DirectoryBuffer::read(&root) {
        Ok(buffer) => buffer.entries().to_vec(),
        Err(error) => {
            let message = format!("failed to read `{}`: {error}", root.display());
            set_directory_error(runtime, buffer_id, &message)?;
            return Err(message);
        }
    };
    let mut state = DirectoryViewState::new(root, entries, defaults);
    state.show_hidden = show_hidden;
    state.sort_mode = sort_mode;
    state.trash_enabled = trash_enabled;
    apply_directory_state(runtime, buffer_id, state)?;
    if previous_root.as_ref() != Some(&root_for_compare) {
        let buffer = shell_buffer_mut(runtime, buffer_id)?;
        let target_line = if buffer.line_count() > 1 { 1 } else { 0 };
        buffer.goto_line(target_line);
        buffer.scroll_row = 0;
    }
    Ok(())
}

fn set_directory_error(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    message: &str,
) -> Result<(), String> {
    record_runtime_error(runtime, "oil.directory", message.to_owned());
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    buffer.clear_directory_state();
    buffer.section_state = None;
    buffer.replace_with_lines(vec![
        "Directory view unavailable.".to_owned(),
        message.to_owned(),
    ]);
    Ok(())
}

fn directory_entry_label(entry: &DirectoryEntry) -> String {
    match entry.kind() {
        DirectoryEntryKind::Directory => format!("{}/", entry.name()),
        DirectoryEntryKind::File => entry.name().to_owned(),
    }
}

fn apply_directory_state(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    state: DirectoryViewState,
) -> Result<(), String> {
    let entries = directory_visible_entries(&state);
    let labels = entries
        .iter()
        .map(directory_entry_label)
        .collect::<Vec<_>>();
    let collapsed = shell_buffer(runtime, buffer_id)?
        .section_state()
        .map(|state| state.collapsed.clone())
        .unwrap_or_default();
    let user_library = shell_user_library(runtime);
    let lines = user_library
        .oil_directory_sections(
            &state.root,
            &entries,
            state.show_hidden,
            state.sort_mode,
            state.trash_enabled,
        )
        .render_lines(&collapsed);
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    {
        let section_state = buffer.ensure_section_state();
        section_state.collapsed = collapsed;
    }
    let mut state = state;
    state.edit_snapshot = labels;
    buffer.set_directory_state(state);
    buffer.set_section_lines(lines);
    Ok(())
}

fn directory_visible_entries(state: &DirectoryViewState) -> Vec<DirectoryEntry> {
    let mut entries = state.entries.clone();
    if !state.show_hidden {
        entries.retain(|entry| !entry.name().starts_with('.'));
    }
    sort_directory_entries(&mut entries, state.sort_mode);
    entries
}

fn sort_directory_entries(entries: &mut [DirectoryEntry], sort_mode: DirectorySortMode) {
    match sort_mode {
        DirectorySortMode::TypeThenName => {
            entries.sort_by(|left, right| {
                let left_is_file = matches!(left.kind(), DirectoryEntryKind::File);
                let right_is_file = matches!(right.kind(), DirectoryEntryKind::File);
                left_is_file.cmp(&right_is_file).then_with(|| {
                    left.name()
                        .to_ascii_lowercase()
                        .cmp(&right.name().to_ascii_lowercase())
                })
            });
        }
        DirectorySortMode::TypeThenNameDesc => {
            entries.sort_by(|left, right| {
                let left_is_file = matches!(left.kind(), DirectoryEntryKind::File);
                let right_is_file = matches!(right.kind(), DirectoryEntryKind::File);
                left_is_file.cmp(&right_is_file).then_with(|| {
                    right
                        .name()
                        .to_ascii_lowercase()
                        .cmp(&left.name().to_ascii_lowercase())
                })
            });
        }
    }
}

fn directory_entry_at_cursor(
    runtime: &EditorRuntime,
    buffer_id: BufferId,
) -> Result<DirectoryEntry, String> {
    let buffer = shell_buffer(runtime, buffer_id)?;
    let state = buffer
        .directory_state()
        .ok_or_else(|| "directory state is missing".to_owned())?;
    let line = buffer.cursor_point().line;
    let meta = buffer
        .section_line_meta(line)
        .and_then(|meta| meta.action.as_ref())
        .ok_or_else(|| "no directory entry selected".to_owned())?;
    if meta.id() != oil_protocol::ACTION_OIL_ENTRY {
        return Err("no directory entry selected".to_owned());
    }
    let detail = meta
        .detail()
        .ok_or_else(|| "directory entry detail missing".to_owned())?;
    let path = Path::new(detail);
    state
        .entries
        .iter()
        .find(|entry| entry.path() == path)
        .cloned()
        .ok_or_else(|| "directory entry not found".to_owned())
}

#[derive(Debug, Clone)]
struct DirectoryLine {
    label: String,
    rel_path: PathBuf,
    is_dir: bool,
}

#[derive(Debug, Clone)]
enum DirectoryEditAction {
    CreateFile(PathBuf),
    CreateDir(PathBuf),
    Delete { path: PathBuf, is_dir: bool },
    Rename { from: PathBuf, to: PathBuf },
}

fn directory_edit_lines(buffer: &ShellBuffer, user_library: &dyn UserLibrary) -> Vec<String> {
    let mut lines = Vec::new();
    for line_index in 0..buffer.line_count() {
        let raw = buffer.text.line(line_index).unwrap_or_default();
        let trimmed = raw.trim();
        if trimmed.is_empty() {
            continue;
        }
        if line_index == 0 && trimmed.starts_with("Directory ") {
            continue;
        }
        lines.push(user_library.oil_strip_entry_icon_prefix(trimmed).to_owned());
    }
    lines
}

fn parse_directory_line(
    line: &str,
    user_library: &dyn UserLibrary,
) -> Result<DirectoryLine, String> {
    let trimmed = user_library.oil_strip_entry_icon_prefix(line.trim());
    let is_dir = trimmed.ends_with('/');
    let raw = trimmed.trim_end_matches('/');
    if raw.is_empty() {
        return Err("directory entry is empty".to_owned());
    }
    let rel_path = PathBuf::from(raw);
    if rel_path.is_absolute() {
        return Err(format!("absolute paths are not supported: {raw}"));
    }
    if rel_path
        .components()
        .any(|component| matches!(component, Component::ParentDir))
    {
        return Err(format!("parent directory segments are not allowed: {raw}"));
    }
    Ok(DirectoryLine {
        label: trimmed.to_owned(),
        rel_path,
        is_dir,
    })
}

#[cfg(test)]
mod directory_line_tests {
    use super::parse_directory_line;
    use editor_plugin_host::NullUserLibrary;
    use std::path::PathBuf;

    #[test]
    fn parse_directory_line_strips_file_icons() {
        let line = format!("{} Cargo.toml", editor_icons::symbols::seti::CUSTOM_TOML);
        let user_library = NullUserLibrary;
        let parsed = parse_directory_line(&line, &user_library)
            .expect("icon-prefixed file line should parse");
        assert_eq!(parsed.label, "Cargo.toml");
        assert_eq!(parsed.rel_path, PathBuf::from("Cargo.toml"));
        assert!(!parsed.is_dir);
    }

    #[test]
    fn parse_directory_line_strips_directory_icons() {
        let line = format!("{} src/", editor_icons::symbols::seti::CUSTOM_FOLDER);
        let user_library = NullUserLibrary;
        let parsed = parse_directory_line(&line, &user_library)
            .expect("icon-prefixed directory line should parse");
        assert_eq!(parsed.label, "src/");
        assert_eq!(parsed.rel_path, PathBuf::from("src"));
        assert!(parsed.is_dir);
    }
}

fn parse_directory_lines(
    lines: &[String],
    user_library: &dyn UserLibrary,
) -> Result<Vec<DirectoryLine>, String> {
    let mut seen = BTreeSet::new();
    let mut parsed = Vec::with_capacity(lines.len());
    for line in lines {
        let entry = parse_directory_line(line, user_library)?;
        if !seen.insert(entry.rel_path.clone()) {
            return Err(format!("duplicate entry `{}`", entry.label));
        }
        parsed.push(entry);
    }
    Ok(parsed)
}

fn diff_directory_lines(before: &[String], after: &[String]) -> (Vec<usize>, Vec<usize>) {
    let before_set = before.iter().collect::<BTreeSet<_>>();
    let after_set = after.iter().collect::<BTreeSet<_>>();
    let removed = before
        .iter()
        .enumerate()
        .filter(|(_, line)| !after_set.contains(line))
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    let added = after
        .iter()
        .enumerate()
        .filter(|(_, line)| !before_set.contains(line))
        .map(|(index, _)| index)
        .collect::<Vec<_>>();
    (removed, added)
}

fn directory_edit_actions(
    root: &Path,
    before: &[String],
    after: &[String],
    user_library: &dyn UserLibrary,
) -> Result<Vec<DirectoryEditAction>, String> {
    if before == after {
        return Ok(Vec::new());
    }
    let before_parsed = parse_directory_lines(before, user_library)?;
    let after_parsed = parse_directory_lines(after, user_library)?;
    let (removed_indices, added_indices) = diff_directory_lines(before, after);
    let removed = removed_indices
        .iter()
        .map(|index| &before_parsed[*index])
        .collect::<Vec<_>>();
    let added = added_indices
        .iter()
        .map(|index| &after_parsed[*index])
        .collect::<Vec<_>>();
    let mut actions = Vec::new();
    let rename_count = if !removed.is_empty() && removed.len() == added.len() {
        removed.len()
    } else {
        0
    };
    for index in 0..rename_count {
        let src = removed[index];
        let dst = added[index];
        if !src.is_dir && dst.is_dir {
            return Err(format!(
                "cannot move file `{}` to directory path `{}`",
                src.label, dst.label
            ));
        }
        actions.push(DirectoryEditAction::Rename {
            from: root.join(&src.rel_path),
            to: root.join(&dst.rel_path),
        });
    }
    for src in removed.iter().skip(rename_count) {
        actions.push(DirectoryEditAction::Delete {
            path: root.join(&src.rel_path),
            is_dir: src.is_dir,
        });
    }
    for dst in added.iter().skip(rename_count) {
        let path = root.join(&dst.rel_path);
        if dst.is_dir {
            actions.push(DirectoryEditAction::CreateDir(path));
        } else {
            actions.push(DirectoryEditAction::CreateFile(path));
        }
    }
    Ok(actions)
}

fn apply_directory_edit_actions(actions: &[DirectoryEditAction]) -> Result<(), String> {
    for action in actions {
        match action {
            DirectoryEditAction::Rename { from, to } => {
                if let Some(parent) = to.parent() {
                    fs::create_dir_all(parent).map_err(|error| {
                        format!("failed to create `{}`: {error}", parent.display())
                    })?;
                }
                fs::rename(from, to)
                    .map_err(|error| format!("failed to move `{}`: {error}", from.display()))?;
            }
            DirectoryEditAction::Delete { path, is_dir } => {
                if *is_dir {
                    fs::remove_dir_all(path).map_err(|error| {
                        format!("failed to remove `{}`: {error}", path.display())
                    })?;
                } else {
                    fs::remove_file(path).map_err(|error| {
                        format!("failed to remove `{}`: {error}", path.display())
                    })?;
                }
            }
            DirectoryEditAction::CreateDir(path) => {
                fs::create_dir_all(path)
                    .map_err(|error| format!("failed to create `{}`: {error}", path.display()))?;
            }
            DirectoryEditAction::CreateFile(path) => {
                if let Some(parent) = path.parent() {
                    fs::create_dir_all(parent).map_err(|error| {
                        format!("failed to create `{}`: {error}", parent.display())
                    })?;
                }
                fs::OpenOptions::new()
                    .write(true)
                    .create_new(true)
                    .open(path)
                    .map_err(|error| format!("failed to create `{}`: {error}", path.display()))?;
            }
        }
    }
    Ok(())
}

fn apply_directory_edit_queue(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    let (root, before) = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        let Some(state) = buffer.directory_state() else {
            return Ok(());
        };
        let snapshot = if state.edit_snapshot.is_empty() {
            directory_visible_entries(state)
                .iter()
                .map(directory_entry_label)
                .collect()
        } else {
            state.edit_snapshot.clone()
        };
        (state.root.clone(), snapshot)
    };
    let after = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        let user_library = shell_user_library(runtime);
        directory_edit_lines(buffer, &*user_library)
    };
    let user_library = shell_user_library(runtime);
    let actions = directory_edit_actions(&root, &before, &after, &*user_library)?;
    if actions.is_empty() {
        return Ok(());
    }
    apply_directory_edit_actions(&actions)?;
    refresh_directory_buffer(runtime, buffer_id)?;
    Ok(())
}

fn update_directory_state(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    update: impl FnOnce(&mut DirectoryViewState),
) -> Result<(), String> {
    let state = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        buffer
            .directory_state()
            .cloned()
            .ok_or_else(|| "directory state is missing".to_owned())?
    };
    let mut state = state;
    update(&mut state);
    apply_directory_state(runtime, buffer_id, state)
}

fn directory_root_for_entry(entry: &DirectoryEntry) -> Result<PathBuf, String> {
    match entry.kind() {
        DirectoryEntryKind::Directory => Ok(entry.path().to_path_buf()),
        DirectoryEntryKind::File => entry
            .path()
            .parent()
            .map(Path::to_path_buf)
            .ok_or_else(|| "entry has no parent directory".to_owned()),
    }
}

fn directory_cd_from_cursor(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    let entry = directory_entry_at_cursor(runtime, buffer_id)?;
    let root = directory_root_for_entry(&entry)?;
    set_directory_root(runtime, buffer_id, root)
}

#[derive(Debug, Clone, Copy)]
enum DirectoryOpenMode {
    Current,
    SplitHorizontal,
    SplitVertical,
    NewPane,
    Preview,
}

fn open_directory_entry(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    entry: DirectoryEntry,
    mode: DirectoryOpenMode,
) -> Result<(), String> {
    match entry.kind() {
        DirectoryEntryKind::Directory => {
            set_directory_root(runtime, buffer_id, entry.path().to_path_buf())
        }
        DirectoryEntryKind::File => match mode {
            DirectoryOpenMode::Current => {
                open_workspace_file(runtime, entry.path())?;
                Ok(())
            }
            DirectoryOpenMode::SplitHorizontal => {
                open_file_in_split(runtime, entry.path(), PaneSplitDirection::Horizontal, true)
            }
            DirectoryOpenMode::SplitVertical => {
                open_file_in_split(runtime, entry.path(), PaneSplitDirection::Vertical, true)
            }
            DirectoryOpenMode::NewPane => {
                open_file_in_split(runtime, entry.path(), PaneSplitDirection::Vertical, true)
            }
            DirectoryOpenMode::Preview => open_oil_preview_popup(runtime, entry.path()),
        },
    }
}

fn open_file_in_split(
    runtime: &mut EditorRuntime,
    path: &Path,
    direction: PaneSplitDirection,
    focus: bool,
) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let original_pane_id = shell_ui(runtime)?
        .active_pane_id()
        .ok_or_else(|| "active pane is missing".to_owned())?;
    if shell_ui(runtime)?.pane_count() < 2 {
        split_runtime_pane(runtime, direction)?;
    }
    let target_pane_id = shell_ui(runtime)?
        .panes()
        .and_then(|panes| {
            panes
                .iter()
                .find(|pane| pane.pane_id != original_pane_id)
                .map(|pane| pane.pane_id)
        })
        .ok_or_else(|| "split pane is missing".to_owned())?;
    runtime
        .model_mut()
        .focus_pane(workspace_id, target_pane_id)
        .map_err(|error| error.to_string())?;
    shell_ui_mut(runtime)?.focus_pane(target_pane_id);
    open_workspace_file(runtime, path)?;
    if !focus {
        runtime
            .model_mut()
            .focus_pane(workspace_id, original_pane_id)
            .map_err(|error| error.to_string())?;
        shell_ui_mut(runtime)?.focus_pane(original_pane_id);
    }
    Ok(())
}

fn open_oil_preview_popup(runtime: &mut EditorRuntime, path: &Path) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let existing = shell_ui(runtime)
        .ok()
        .and_then(|ui| find_shell_buffer_by_kind(ui, OIL_PREVIEW_KIND));
    let buffer_id = if let Some(existing) = existing {
        existing
    } else {
        runtime
            .model_mut()
            .create_popup_buffer(
                workspace_id,
                OIL_PREVIEW_BUFFER_NAME,
                BufferKind::Plugin(OIL_PREVIEW_KIND.to_owned()),
                None,
            )
            .map_err(|error| error.to_string())?
    };
    runtime
        .model_mut()
        .open_popup_buffer(workspace_id, "Preview", buffer_id)
        .map_err(|error| error.to_string())?;
    shell_ui_mut(runtime)?.set_popup_focus(false);
    let buffer = runtime
        .model()
        .workspace(workspace_id)
        .map_err(|error| error.to_string())?
        .buffer(buffer_id)
        .ok_or_else(|| format!("buffer `{buffer_id}` is missing"))?;
    let text = TextBuffer::load_from_path(path)
        .map_err(|error| format!("failed to open `{}`: {error}", path.display()))?;
    let user_library = shell_user_library(runtime);
    let shell_buffer = ShellBuffer::from_text_buffer(buffer, text, &*user_library);
    shell_ui_mut(runtime)?.insert_buffer(shell_buffer);
    queue_buffer_syntax_refresh(runtime, buffer_id)?;
    Ok(())
}

fn open_oil_help_popup(runtime: &mut EditorRuntime) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let existing = shell_ui(runtime)
        .ok()
        .and_then(|ui| find_shell_buffer_by_kind(ui, OIL_HELP_KIND));
    let buffer_id = if let Some(existing) = existing {
        existing
    } else {
        runtime
            .model_mut()
            .create_popup_buffer(
                workspace_id,
                OIL_HELP_BUFFER_NAME,
                BufferKind::Plugin(OIL_HELP_KIND.to_owned()),
                None,
            )
            .map_err(|error| error.to_string())?
    };
    runtime
        .model_mut()
        .open_popup_buffer(workspace_id, "Oil Help", buffer_id)
        .map_err(|error| error.to_string())?;
    {
        let ui = shell_ui_mut(runtime)?;
        ui.set_popup_buffer(buffer_id);
        ui.set_popup_focus(true);
    }
    let buffer = runtime
        .model()
        .workspace(workspace_id)
        .map_err(|error| error.to_string())?
        .buffer(buffer_id)
        .ok_or_else(|| format!("buffer `{buffer_id}` is missing"))?;
    let user_library = shell_user_library(runtime);
    let shell_buffer =
        ShellBuffer::from_runtime_buffer(buffer, user_library.oil_help_lines(), &*user_library);
    shell_ui_mut(runtime)?.insert_buffer(shell_buffer);
    Ok(())
}

fn open_external_path(path: &Path) -> Result<(), String> {
    if !path.exists() {
        return Err(format!("path does not exist: {}", path.display()));
    }
    #[cfg(target_os = "windows")]
    {
        let mut command = Command::new("cmd");
        configure_background_command(&mut command);
        command
            .arg("/C")
            .arg("start")
            .arg("")
            .arg(path)
            .stdin(std::process::Stdio::null())
            .stdout(std::process::Stdio::null())
            .stderr(std::process::Stdio::null())
            .spawn()
            .map_err(|error| format!("failed to open `{}`: {error}", path.display()))?;
    }
    #[cfg(target_os = "macos")]
    {
        Command::new("open")
            .arg(path)
            .spawn()
            .map_err(|error| format!("failed to open `{}`: {error}", path.display()))?;
    }
    #[cfg(target_os = "linux")]
    {
        Command::new("xdg-open")
            .arg(path)
            .spawn()
            .map_err(|error| format!("failed to open `{}`: {error}", path.display()))?;
    }
    Ok(())
}

fn open_git_commit_buffer(runtime: &mut EditorRuntime) -> Result<(), String> {
    let existing = shell_ui(runtime)
        .ok()
        .and_then(|ui| find_shell_buffer_by_kind(ui, GIT_COMMIT_KIND));
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    if let Some(existing) = existing {
        runtime
            .model_mut()
            .focus_buffer(workspace_id, existing)
            .map_err(|error| error.to_string())?;
        let ui = shell_ui_mut(runtime)?;
        ui.focus_buffer_in_active_pane(existing);
        ui.enter_normal_mode();
        return Ok(());
    }
    let buffer_id = {
        runtime
            .model_mut()
            .create_buffer(
                workspace_id,
                "*git-commit*",
                BufferKind::Plugin(GIT_COMMIT_KIND.to_owned()),
                None,
            )
            .map_err(|error| error.to_string())?
    };
    let buffer = runtime
        .model()
        .workspace(workspace_id)
        .map_err(|error| error.to_string())?
        .buffer(buffer_id)
        .ok_or_else(|| format!("buffer `{buffer_id}` is missing"))?;
    let template = shell_user_library(runtime).git_commit_template();
    let user_library = shell_user_library(runtime);
    let mut shell_buffer = ShellBuffer::from_runtime_buffer(buffer, template, &*user_library);
    shell_buffer.set_language_id(Some("gitcommit".to_owned()));
    {
        let ui = shell_ui_mut(runtime)?;
        ui.insert_buffer(shell_buffer);
        ui.focus_buffer_in_active_pane(buffer_id);
        ui.enter_normal_mode();
    }
    queue_buffer_syntax_refresh(runtime, buffer_id)
}

fn git_commit_temp_path() -> PathBuf {
    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_else(|_| Duration::from_secs(0))
        .as_nanos();
    env::temp_dir().join(format!(
        "volt-git-commit-{}-{unique}.txt",
        std::process::id()
    ))
}

fn git_commit_message(buffer: &ShellBuffer) -> String {
    let raw = buffer.text.text();
    let mut lines = Vec::new();
    for line in raw.lines() {
        let trimmed = line.trim_end();
        if trimmed.trim_start().starts_with('#') {
            continue;
        }
        lines.push(trimmed);
    }
    lines.join("\n").trim().to_owned()
}

fn commit_git_buffer(runtime: &mut EditorRuntime, buffer_id: BufferId) -> Result<(), String> {
    let root = git_root(runtime)?;
    let message = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        git_commit_message(buffer)
    };
    if message.trim().is_empty() {
        return Err("commit message is empty".to_owned());
    }
    let temp_path = git_commit_temp_path();
    fs::write(&temp_path, &message)
        .map_err(|error| format!("failed to write commit message: {error}"))?;
    let result = git_command_output(
        runtime,
        &root,
        "commit",
        &["commit", "-F", &temp_path.to_string_lossy()],
    );
    fs::remove_file(&temp_path).ok();
    result?;
    close_buffer_discard(runtime, buffer_id)?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

fn cancel_git_commit_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    close_buffer_discard(runtime, buffer_id)?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

/// Evaluate the input section of any evaluatable plugin buffer and replace the
/// output section with the result.  Called both by the generic Ctrl+c Ctrl+c
/// handler and by the `plugin.evaluate` hook subscriber.
fn evaluate_active_plugin_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
) -> Result<(), String> {
    // Read the buffer kind (needed to route the evaluate call).
    let (input_lines, sep_line, kind_str, has_plugin_sections) = {
        let buffer = shell_buffer(runtime, buffer_id)?;
        let kind_str = if let BufferKind::Plugin(k) = &buffer.kind {
            k.clone()
        } else {
            return Ok(()); // not a plugin buffer; nothing to do
        };
        if buffer.has_plugin_sections() {
            let line_count = buffer.text.line_count();
            let all_lines: Vec<String> = (0..line_count)
                .map(|i| buffer.text.line(i).unwrap_or_default().to_owned())
                .collect();
            (all_lines, String::new(), kind_str, true)
        } else {
            let line_count = buffer.text.line_count();
            let all_lines: Vec<String> = (0..line_count)
                .map(|i| buffer.text.line(i).unwrap_or_default().to_owned())
                .collect();
            if let Some(idx) = all_lines
                .iter()
                .position(|l| l.starts_with(PLUGIN_EVALUATE_SEPARATOR_PREFIX))
            {
                let input = all_lines[..idx].to_vec();
                let sep = all_lines[idx].clone();
                (input, sep, kind_str, false)
            } else {
                // No separator — treat everything as input; add a fresh separator.
                let sep = format!("{} {}", PLUGIN_EVALUATE_SEPARATOR_PREFIX, "─".repeat(48));
                (all_lines, sep, kind_str, false)
            }
        }
    };

    let input_text = input_lines.join("\n");

    // Call user library evaluator (no mutable borrow of runtime required).
    let output = shell_user_library(runtime).handle_plugin_evaluate(&kind_str, &input_text);

    if has_plugin_sections {
        shell_buffer_mut(runtime, buffer_id)?.set_plugin_output_lines(output);
        return Ok(());
    }

    // Rebuild: input + separator + output.
    let mut new_lines = input_lines;
    new_lines.push(sep_line);
    new_lines.extend(output);

    shell_buffer_mut(runtime, buffer_id)?.replace_with_lines(new_lines);
    Ok(())
}

fn switch_active_plugin_pane(
    runtime: &mut EditorRuntime,
    buffer_id: Option<BufferId>,
) -> Result<(), String> {
    let buffer_id = buffer_id.unwrap_or(active_shell_buffer_id(runtime)?);
    let switched_to_read_only = {
        let buffer = shell_buffer_mut(runtime, buffer_id)?;
        if buffer.plugin_switch_pane() {
            buffer.is_read_only()
        } else {
            return acp::acp_switch_pane(runtime);
        }
    };
    if switched_to_read_only {
        shell_ui_mut(runtime)?.enter_normal_mode();
    }
    Ok(())
}

// ─── Generic compile / build infrastructure ───────────────────────────────────

/// Buffer name pattern for the compilation popup.
fn compile_buffer_name(workspace_name: &str) -> String {
    format!("*compile {workspace_name}*")
}

fn command_output_buffer_name(workspace_name: &str) -> String {
    format!("*command {workspace_name}*")
}

/// Open (or focus) the `*compile <workspace>*` compilation buffer and
/// pre-fill its input field with the default build command for `language`
/// (obtained from the user library).  The user can edit the command and press
/// Ctrl+Enter to run it.
///
/// Called by the `plugin.run-command` hook subscriber.
fn open_compile_buffer(
    runtime: &mut EditorRuntime,
    language_hint: Option<&str>,
) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let workspace_name = runtime
        .model()
        .active_workspace()
        .map_err(|error| error.to_string())?
        .name()
        .to_owned();
    let buf_name = compile_buffer_name(&workspace_name);

    // Reuse an existing buffer if present.
    let existing = shell_ui(runtime).ok().and_then(|ui| {
        ui.buffers
            .iter()
            .find(|b| b.display_name() == buf_name)
            .map(|b| b.id())
    });

    let buffer_id = if let Some(existing) = existing {
        runtime
            .model_mut()
            .focus_buffer(workspace_id, existing)
            .map_err(|error| error.to_string())?;
        let ui = shell_ui_mut(runtime)?;
        ui.focus_buffer_in_active_pane(existing);
        ui.enter_normal_mode();
        existing
    } else {
        let id = runtime
            .model_mut()
            .create_buffer(workspace_id, &buf_name, BufferKind::Compilation, None)
            .map_err(|error| error.to_string())?;
        let buffer = runtime
            .model()
            .workspace(workspace_id)
            .map_err(|e| e.to_string())?
            .buffer(id)
            .ok_or_else(|| format!("buffer `{id}` is missing"))?;
        let user_library = shell_user_library(runtime);
        let initial = vec![format!("# {workspace_name} — compilation output")];
        let mut shell_buf = ShellBuffer::from_runtime_buffer(buffer, initial, &*user_library);
        // Pre-fill the input field with the default build command.
        let default_cmd = language_hint
            .and_then(|lang| user_library.default_build_command(lang))
            .unwrap_or_default();
        if let Some(input) = shell_buf.input_field_mut() {
            input.set_text(&default_cmd);
        }
        let ui = shell_ui_mut(runtime)?;
        ui.insert_buffer(shell_buf);
        ui.focus_buffer_in_active_pane(id);
        ui.enter_normal_mode();
        id
    };

    // If the buffer already has a stored command for this workspace, pre-fill it.
    let stored = shell_ui(runtime)
        .ok()
        .and_then(|ui| ui.compile_commands.get(&workspace_id).cloned());
    if let Some(cmd) = stored
        && let Some(buf) = shell_ui_mut(runtime)
            .ok()
            .and_then(|ui| ui.buffer_mut(buffer_id))
        && let Some(input) = buf.input_field_mut()
    {
        input.set_text(&cmd);
    }

    Ok(())
}

fn open_command_output_buffer(runtime: &mut EditorRuntime) -> Result<BufferId, String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let workspace_name = runtime
        .model()
        .active_workspace()
        .map_err(|error| error.to_string())?
        .name()
        .to_owned();
    let buf_name = command_output_buffer_name(&workspace_name);
    let existing = shell_ui(runtime).ok().and_then(|ui| {
        ui.buffers
            .iter()
            .find(|buffer| buffer.display_name() == buf_name)
            .map(ShellBuffer::id)
    });
    if let Some(existing) = existing {
        runtime
            .model_mut()
            .focus_buffer(workspace_id, existing)
            .map_err(|error| error.to_string())?;
        let ui = shell_ui_mut(runtime)?;
        ui.focus_buffer_in_active_pane(existing);
        ui.enter_normal_mode();
        return Ok(existing);
    }
    let id = runtime
        .model_mut()
        .create_buffer(workspace_id, &buf_name, BufferKind::Compilation, None)
        .map_err(|error| error.to_string())?;
    let buffer = runtime
        .model()
        .workspace(workspace_id)
        .map_err(|error| error.to_string())?
        .buffer(id)
        .ok_or_else(|| format!("buffer `{id}` is missing"))?;
    let user_library = shell_user_library(runtime);
    let initial = vec![format!("# {workspace_name} — command output")];
    let shell_buf = ShellBuffer::from_runtime_buffer(buffer, initial, &*user_library);
    let ui = shell_ui_mut(runtime)?;
    ui.insert_buffer(shell_buf);
    ui.focus_buffer_in_active_pane(id);
    ui.enter_normal_mode();
    Ok(id)
}

fn run_shell_command_from_vim_command_line(
    runtime: &mut EditorRuntime,
    command: &str,
) -> Result<(), String> {
    let command = command.trim();
    if command.is_empty() {
        return Err(":! requires a shell command".to_owned());
    }
    let buffer_id = open_command_output_buffer(runtime)?;
    run_shell_command_in_buffer(runtime, buffer_id, command)
}

fn run_shell_command_in_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    command: &str,
) -> Result<(), String> {
    let command = command.trim().to_owned();
    if command.is_empty() {
        return Ok(());
    }
    let terminal_config = shell_user_library(runtime).terminal_config();
    let cwd = active_workspace_root(runtime)
        .ok()
        .flatten()
        .unwrap_or_else(|| std::env::current_dir().unwrap_or_else(|_| PathBuf::from(".")));
    let mut args = terminal_config.args;
    let shell_program = terminal_config.program;
    args.push(shell_command_eval_flag(&shell_program).to_owned());
    args.push(command.clone());
    {
        let buffer = shell_buffer_mut(runtime, buffer_id)?;
        buffer.append_output_lines(&[format!("$ {command}"), String::new()]);
        buffer.clear_input();
    }
    let spec = JobSpec::command("command", shell_program, args).with_cwd(cwd);
    let manager = runtime
        .services()
        .get::<Mutex<JobManager>>()
        .ok_or_else(|| "job manager service missing".to_owned())?;
    let mut manager = manager
        .lock()
        .map_err(|_| "job manager lock poisoned".to_owned())?;
    let handle = manager.spawn(spec).map_err(|error| error.to_string())?;
    drop(manager);
    let result = handle.wait().map_err(|error| error.to_string())?;
    let transcript = result.transcript();
    let output_lines: Vec<String> = transcript.lines().map(str::to_owned).collect();
    let status_line = if result.succeeded() {
        "── ✓ Command succeeded ────────────────────────────────────────────────".to_owned()
    } else {
        format!(
            "── ✗ Command failed (exit {}) ──────────────────────────────────────",
            result.exit_code().unwrap_or(-1)
        )
    };
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    buffer.append_output_lines(&output_lines);
    buffer.append_output_lines(&[status_line]);
    Ok(())
}

fn shell_command_eval_flag(program: &str) -> &'static str {
    let shell = Path::new(program)
        .file_stem()
        .and_then(|stem| stem.to_str())
        .unwrap_or_default();
    if cfg!(target_os = "windows") {
        if shell.eq_ignore_ascii_case("cmd") {
            "/C"
        } else if shell.eq_ignore_ascii_case("powershell") || shell.eq_ignore_ascii_case("pwsh") {
            "-Command"
        } else {
            "-c"
        }
    } else {
        "-c"
    }
}

/// Re-run the last stored build command for the active workspace.
/// If no command has been stored yet, falls back to opening the compile buffer.
fn rerun_compile_command(runtime: &mut EditorRuntime) -> Result<(), String> {
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    let stored = shell_ui(runtime)
        .ok()
        .and_then(|ui| ui.compile_commands.get(&workspace_id).cloned());
    if let Some(cmd) = stored {
        let workspace_name = runtime
            .model()
            .active_workspace()
            .map_err(|error| error.to_string())?
            .name()
            .to_owned();
        let buf_name = compile_buffer_name(&workspace_name);
        let buf_id = shell_ui(runtime).ok().and_then(|ui| {
            ui.buffers
                .iter()
                .find(|b| b.display_name() == buf_name)
                .map(|b| b.id())
        });
        if let Some(buffer_id) = buf_id {
            run_compile_command_in_buffer(runtime, buffer_id, &cmd)
        } else {
            open_compile_buffer(runtime, None)
        }
    } else {
        open_compile_buffer(runtime, None)
    }
}

/// Run `command` in the compilation buffer `buffer_id`, capturing stdout +
/// stderr into it.  Stores the command as the active workspace's last command.
fn run_compile_command_in_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    command: &str,
) -> Result<(), String> {
    let command = command.trim().to_owned();
    if command.is_empty() {
        return Ok(());
    }

    // Parse into program + args.
    let mut parts = command.split_whitespace();
    let program = parts.next().unwrap_or("").to_owned();
    let args: Vec<String> = parts.map(str::to_owned).collect();

    // Determine working directory (workspace root or cwd).
    let cwd = active_workspace_root(runtime)
        .ok()
        .flatten()
        .unwrap_or_else(|| std::env::current_dir().unwrap_or_else(|_| PathBuf::from(".")));

    // Store command for this workspace.
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|e| e.to_string())?;
    if let Ok(ui) = shell_ui_mut(runtime) {
        ui.compile_commands.insert(workspace_id, command.clone());
    }

    // Write header to buffer.
    {
        let buf = shell_buffer_mut(runtime, buffer_id)?;
        buf.append_output_lines(&[format!("$ {command}"), String::new()]);
        buf.clear_input();
    }

    // Spawn the job and wait (synchronously — same pattern as git commands).
    let spec = JobSpec::command("compile", &program, args).with_cwd(cwd);
    let manager = runtime
        .services()
        .get::<Mutex<JobManager>>()
        .ok_or_else(|| "job manager service missing".to_owned())?;
    let mut manager = manager
        .lock()
        .map_err(|_| "job manager lock poisoned".to_owned())?;
    let handle = manager.spawn(spec).map_err(|e| e.to_string())?;
    drop(manager);
    let result = handle.wait().map_err(|e| e.to_string())?;

    // Write output to the buffer.
    let transcript = result.transcript();
    let output_lines: Vec<String> = transcript.lines().map(str::to_owned).collect();
    let status_line = if result.succeeded() {
        "── ✓ Build succeeded ──────────────────────────────────────────────────".to_owned()
    } else {
        format!(
            "── ✗ Build failed (exit {}) ─────────────────────────────────────────",
            result.exit_code().unwrap_or(-1)
        )
    };
    let buf = shell_buffer_mut(runtime, buffer_id)?;
    buf.append_output_lines(&output_lines);
    buf.append_output_lines(&[status_line]);
    Ok(())
}

/// In a compilation buffer, jump to the file location on the current line
/// by parsing `path:line` or `path:line:col`.
fn jump_to_compilation_error(runtime: &mut EditorRuntime) -> Result<(), String> {
    let buffer_id = active_shell_buffer_id(runtime)?;
    let line_text = {
        let buf = shell_buffer(runtime, buffer_id)?;
        let cursor_line = buf.cursor_point().line;
        buf.text.line(cursor_line).unwrap_or_default().to_owned()
    };

    // Parse the error line via the user library's compile module pattern.
    // We use the same logic as user::compile::parse_error_location but replicated
    // here generically so the shell does not depend on user code at parse time.
    let parsed = parse_compilation_error_line(&line_text);
    let (path, line_num, _col) = match parsed {
        Some(loc) => loc,
        None => return Ok(()), // not an error line, silently ignore
    };

    // Determine the absolute path (relative to workspace root if needed).
    let root = active_workspace_root(runtime).ok().flatten();
    let abs_path = if std::path::Path::new(&path).is_absolute() {
        PathBuf::from(&path)
    } else if let Some(ref root) = root {
        root.join(&path)
    } else {
        PathBuf::from(&path)
    };

    // Find or open the file buffer and navigate to the line.
    open_file_at_line(runtime, &abs_path, line_num)
}

/// Generic compilation error line parser.  Handles:
/// - `path:line:col`
/// - `path:line`
/// - `  --> path:line:col` (Rust rustc style)
fn parse_compilation_error_line(line: &str) -> Option<(String, u32, u32)> {
    let line = line.trim();
    let line = line.strip_prefix("-->").map(str::trim).unwrap_or(line);
    let parts: Vec<&str> = line.splitn(4, ':').collect();
    match parts.as_slice() {
        [path, line_str, col_str, ..] => {
            let line_num = line_str.trim().parse::<u32>().ok()?;
            let col_num = col_str
                .trim()
                .split_once(|c: char| !c.is_ascii_digit())
                .and_then(|(n, _)| n.parse().ok())
                .or_else(|| col_str.trim().parse().ok())
                .unwrap_or(1);
            if !path.is_empty() && line_num > 0 {
                return Some(((*path).to_owned(), line_num, col_num));
            }
            None
        }
        [path, line_str] => {
            let line_num = line_str.trim().parse::<u32>().ok()?;
            if !path.is_empty() && line_num > 0 {
                return Some(((*path).to_owned(), line_num, 1));
            }
            None
        }
        _ => None,
    }
}

/// Open `path` in the most-recently-active non-compilation buffer and move
/// the cursor to `line_num`.
fn open_file_at_line(
    runtime: &mut EditorRuntime,
    path: &Path,
    line_num: u32,
) -> Result<(), String> {
    open_workspace_file_at(
        runtime,
        path,
        TextPoint::new(line_num.saturating_sub(1) as usize, 0),
    )?;
    shell_ui_mut(runtime)?.enter_normal_mode();
    Ok(())
}

fn stage_git_files(runtime: &mut EditorRuntime, paths: &[String]) -> Result<(), String> {
    if paths.is_empty() {
        return Ok(());
    }
    let root = git_root(runtime)?;
    let mut args = vec!["add".to_owned(), "--".to_owned()];
    args.extend(paths.iter().cloned());
    git_command_output_owned(runtime, &root, "add", &args)?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

fn stage_git_all(runtime: &mut EditorRuntime) -> Result<(), String> {
    let root = git_root(runtime)?;
    git_command_output(runtime, &root, "add -A", &["add", "-A"])?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

fn unstage_git_files(runtime: &mut EditorRuntime, paths: &[String]) -> Result<(), String> {
    if paths.is_empty() {
        return Ok(());
    }
    let root = git_root(runtime)?;
    let mut args = vec!["reset".to_owned(), "-q".to_owned(), "--".to_owned()];
    args.extend(paths.iter().cloned());
    git_command_output_owned(runtime, &root, "reset --", &args)?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

fn unstage_git_all(runtime: &mut EditorRuntime) -> Result<(), String> {
    let root = git_root(runtime)?;
    git_command_output(runtime, &root, "reset", &["reset", "-q"])?;
    refresh_git_status_if_active(runtime)?;
    Ok(())
}

fn git_action_detail(meta: Option<&SectionLineMeta>, action_id: &str) -> Option<String> {
    meta.and_then(|meta| meta.action.as_ref())
        .filter(|action| action.id() == action_id)
        .and_then(|action| action.detail())
        .map(str::to_owned)
}

#[derive(Debug, Clone)]
struct GitDeleteTarget {
    path: String,
    untracked: bool,
}

fn git_status_delete_target_for_line(
    buffer: &ShellBuffer,
    line_index: usize,
) -> Option<GitDeleteTarget> {
    let meta = buffer.section_line_meta(line_index)?;
    let action = meta.action.as_ref()?;
    let path = action.detail()?;
    if action.id() == GIT_ACTION_UNSTAGE_FILE {
        return Some(GitDeleteTarget {
            path: path.to_owned(),
            untracked: false,
        });
    }
    if action.id() == GIT_ACTION_STAGE_FILE {
        return Some(GitDeleteTarget {
            path: path.to_owned(),
            untracked: git_line_is_untracked(Some(meta)),
        });
    }
    None
}

fn visual_selection_line_range(selection: VisualSelection) -> Option<(usize, usize)> {
    match selection {
        VisualSelection::Range(range) => {
            let start_line = range.start().line;
            let mut end_line = range.end().line;
            if range.end().column == 0 && end_line > start_line {
                end_line = end_line.saturating_sub(1);
            }
            Some((start_line, end_line.max(start_line)))
        }
        VisualSelection::Block(selection) => Some((selection.start_line, selection.end_line)),
    }
}

fn git_status_selected_lines(
    runtime: &EditorRuntime,
    buffer_id: BufferId,
) -> Result<(Vec<usize>, bool), String> {
    let ui = shell_ui(runtime)?;
    let is_visual = matches!(ui.input_mode(), InputMode::Visual);
    let buffer = shell_buffer(runtime, buffer_id)?;
    if !is_visual {
        return Ok((vec![buffer.cursor_point().line], false));
    }

    let anchor = ui
        .vim()
        .visual_anchor
        .ok_or_else(|| "visual selection anchor is missing".to_owned())?;
    let selection = visual_selection(buffer, anchor, ui.vim().visual_kind)
        .ok_or_else(|| "visual selection is empty".to_owned())?;
    let (start_line, end_line) = visual_selection_line_range(selection).unwrap_or((0, 0));
    let end_line = end_line.min(buffer.line_count().saturating_sub(1));
    Ok(((start_line..=end_line).collect(), true))
}

fn git_status_action_targets(
    runtime: &EditorRuntime,
    buffer_id: BufferId,
    action_id: &str,
) -> Result<(Vec<String>, bool), String> {
    let (selected_lines, is_visual) = git_status_selected_lines(runtime, buffer_id)?;
    let buffer = shell_buffer(runtime, buffer_id)?;
    let mut targets = BTreeSet::new();
    for line_index in selected_lines {
        if let Some(path) = git_action_detail(buffer.section_line_meta(line_index), action_id) {
            targets.insert(path);
        }
    }
    Ok((targets.into_iter().collect(), is_visual))
}

fn git_status_delete_targets(
    runtime: &EditorRuntime,
    buffer_id: BufferId,
) -> Result<(Vec<GitDeleteTarget>, bool), String> {
    let (selected_lines, is_visual) = git_status_selected_lines(runtime, buffer_id)?;
    let buffer = shell_buffer(runtime, buffer_id)?;
    let mut targets = BTreeMap::new();
    for line_index in selected_lines {
        if let Some(target) = git_status_delete_target_for_line(buffer, line_index) {
            targets.entry(target.path.clone()).or_insert(target);
        }
    }
    Ok((targets.into_values().collect(), is_visual))
}

fn delete_git_status_targets(
    runtime: &mut EditorRuntime,
    targets: &[GitDeleteTarget],
) -> Result<(), String> {
    if targets.is_empty() {
        return Ok(());
    }
    let root = git_root(runtime)?;
    for target in targets {
        if target.untracked {
            let path = root.join(&target.path);
            let metadata = fs::metadata(&path)
                .map_err(|error| format!("failed to stat `{}`: {error}", path.display()))?;
            if metadata.is_dir() {
                fs::remove_dir_all(&path)
                    .map_err(|error| format!("failed to remove `{}`: {error}", path.display()))?;
            } else {
                fs::remove_file(&path)
                    .map_err(|error| format!("failed to remove `{}`: {error}", path.display()))?;
            }
        } else {
            let args = ["rm", "-f", "--ignore-unmatch", "--", target.path.as_str()];
            git_command_output(runtime, &root, "rm -f", &args)?;
        }
    }
    refresh_git_status_buffers(runtime)?;
    Ok(())
}

fn git_line_is_untracked(meta: Option<&SectionLineMeta>) -> bool {
    meta.is_some_and(|meta| meta.section_id == GIT_SECTION_UNTRACKED)
}

fn git_args_with_no_pager(command: &str, extra: &[&str]) -> Vec<String> {
    let mut args = Vec::with_capacity(2 + extra.len());
    args.push("--no-pager".to_owned());
    args.push(command.to_owned());
    args.extend(extra.iter().map(|arg| (*arg).to_owned()));
    args
}

fn git_view_lines(runtime: &mut EditorRuntime, view: &GitViewState) -> Result<Vec<String>, String> {
    let root = git_root(runtime)?;
    let args = view.args.iter().map(String::as_str).collect::<Vec<_>>();
    let output = git_command_output_allow_exit_codes(
        runtime,
        &root,
        &view.label,
        &args,
        &view.allowed_exit_codes,
    )?;
    let mut lines = output
        .lines()
        .map(|line| line.to_owned())
        .collect::<Vec<_>>();
    if lines.is_empty() {
        lines.push(view.empty_message.clone());
    }
    Ok(lines)
}

fn git_view_lines_or_error(runtime: &mut EditorRuntime, view: &GitViewState) -> Vec<String> {
    match git_view_lines(runtime, view) {
        Ok(lines) => lines,
        Err(error) => {
            record_runtime_error(runtime, &format!("git.{}", view.label), error.clone());
            vec![format!("Git {} unavailable.", view.label), error]
        }
    }
}

fn open_git_view_buffer(
    runtime: &mut EditorRuntime,
    kind: &str,
    name: &str,
    view: GitViewState,
) -> Result<(), String> {
    let lines = git_view_lines_or_error(runtime, &view);
    let existing = shell_ui(runtime)
        .ok()
        .and_then(|ui| find_shell_buffer_by_kind(ui, kind));
    let workspace_id = runtime
        .model()
        .active_workspace_id()
        .map_err(|error| error.to_string())?;
    if let Some(existing) = existing {
        runtime
            .model_mut()
            .focus_buffer(workspace_id, existing)
            .map_err(|error| error.to_string())?;
        let ui = shell_ui_mut(runtime)?;
        ui.focus_buffer_in_active_pane(existing);
        let buffer = shell_buffer_mut(runtime, existing)?;
        buffer.set_git_view(view);
        buffer.replace_with_lines(lines);
        return Ok(());
    }

    let buffer_id = runtime
        .model_mut()
        .create_buffer(
            workspace_id,
            name,
            BufferKind::Plugin(kind.to_owned()),
            None,
        )
        .map_err(|error| error.to_string())?;
    let buffer = runtime
        .model()
        .workspace(workspace_id)
        .map_err(|error| error.to_string())?
        .buffer(buffer_id)
        .ok_or_else(|| format!("buffer `{buffer_id}` is missing"))?;
    let user_library = shell_user_library(runtime);
    let mut shell_buffer = ShellBuffer::from_runtime_buffer(buffer, lines, &*user_library);
    shell_buffer.set_git_view(view);
    let ui = shell_ui_mut(runtime)?;
    ui.insert_buffer(shell_buffer);
    ui.focus_buffer_in_active_pane(buffer_id);
    Ok(())
}

fn apply_git_view(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    view: GitViewState,
) -> Result<(), String> {
    let lines = git_view_lines_or_error(runtime, &view);
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    buffer.set_git_view(view);
    buffer.replace_with_lines(lines);
    Ok(())
}

fn open_git_diff_buffer(runtime: &mut EditorRuntime, view: GitViewState) -> Result<(), String> {
    open_git_view_buffer(runtime, GIT_DIFF_KIND, "*git-diff*", view)
}

