fn apply_undo_tree_node(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    node_id: usize,
) -> Result<(), String> {
    let buffer = shell_buffer_mut(runtime, buffer_id)?;
    if buffer.undo_tree_select(node_id) {
        buffer.mark_syntax_dirty();
        Ok(())
    } else {
        Err("undo tree node is missing".to_owned())
    }
}

fn workspace_relative_path(root: Option<&Path>, path: &Path) -> String {
    root.and_then(|root| path.strip_prefix(root).ok())
        .unwrap_or(path)
        .display()
        .to_string()
}

fn workspace_search_entries(root: &Path, query: &str) -> SearchPickerData {
    let query = query.trim();
    if query.is_empty() {
        return SearchPickerData {
            entries: Vec::new(),
            selected_index: 0,
        };
    }

    let entries = match workspace_search_output(root, query) {
        Ok(output) => {
            let parsed = parse_workspace_search_entries(root, query, &output);
            if parsed.is_empty() {
                vec![workspace_search_status_entry(
                    query,
                    "No matches found",
                    format!("No workspace results for `{query}`."),
                    Some(root.display().to_string()),
                )]
            } else {
                parsed
            }
        }
        Err(error) => vec![workspace_search_status_entry(
            query,
            "Search unavailable",
            error,
            Some(root.display().to_string()),
        )],
    };

    SearchPickerData {
        entries,
        selected_index: 0,
    }
}

fn workspace_search_output(root: &Path, query: &str) -> Result<String, String> {
    match workspace_search_rg_output(root, query) {
        Ok(output) => Ok(output),
        Err(rg_error) => workspace_search_grep_output(root, query).map_err(|grep_error| {
            format!("workspace search requires `rg` or `grep`: {rg_error}; {grep_error}")
        }),
    }
}

fn workspace_search_rg_output(root: &Path, query: &str) -> Result<String, String> {
    let mut args = vec![
        "--vimgrep".to_owned(),
        "--no-heading".to_owned(),
        "--color".to_owned(),
        "never".to_owned(),
        "--fixed-strings".to_owned(),
    ];
    if !search_is_case_sensitive(query) {
        args.push("--ignore-case".to_owned());
    }
    args.push("--".to_owned());
    args.push(query.to_owned());
    args.push(".".to_owned());
    run_search_command(root, "rg", &args)
}

fn workspace_search_grep_output(root: &Path, query: &str) -> Result<String, String> {
    let mut args = vec![
        "-R".to_owned(),
        "-n".to_owned(),
        "-F".to_owned(),
        "--binary-files=without-match".to_owned(),
        "--exclude-dir=.git".to_owned(),
    ];
    if !search_is_case_sensitive(query) {
        args.push("-i".to_owned());
    }
    args.push("--".to_owned());
    args.push(query.to_owned());
    args.push(".".to_owned());
    run_search_command(root, "grep", &args)
}

fn run_search_command(root: &Path, command: &str, args: &[String]) -> Result<String, String> {
    let mut process = Command::new(command);
    configure_background_command(&mut process);
    let output = process
        .args(args)
        .current_dir(root)
        .output()
        .map_err(|error| format!("failed to run `{command}`: {error}"))?;
    let exit_code = output
        .status
        .code()
        .ok_or_else(|| format!("`{command}` terminated unexpectedly"))?;
    if exit_code != 0 && exit_code != 1 {
        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_owned();
        let message = if stderr.is_empty() {
            format!("`{command}` exited with status {exit_code}")
        } else {
            format!("`{command}` exited with status {exit_code}: {stderr}")
        };
        return Err(message);
    }
    Ok(String::from_utf8_lossy(&output.stdout).into_owned())
}

fn parse_workspace_search_entries(root: &Path, query: &str, output: &str) -> Vec<PickerEntry> {
    output
        .lines()
        .filter_map(|line| {
            parse_rg_workspace_search_line(line)
                .or_else(|| parse_grep_workspace_search_line(line, query))
                .map(|(relative_path, line_number, column, line_text)| {
                    workspace_search_match_entry(
                        root,
                        &relative_path,
                        line_number,
                        column,
                        &line_text,
                    )
                })
        })
        .take(SEARCH_PICKER_ITEM_LIMIT)
        .collect()
}

fn parse_rg_workspace_search_line(line: &str) -> Option<(String, usize, usize, String)> {
    let mut parts = line.splitn(4, ':');
    let relative_path = parts.next()?.to_owned();
    let line_number = parts.next()?.parse::<usize>().ok()?;
    let column = parts.next()?.parse::<usize>().ok()?;
    let line_text = parts.next()?.to_owned();
    Some((relative_path, line_number, column, line_text))
}

fn parse_grep_workspace_search_line(
    line: &str,
    query: &str,
) -> Option<(String, usize, usize, String)> {
    let mut parts = line.splitn(3, ':');
    let relative_path = parts.next()?.to_owned();
    let line_number = parts.next()?.parse::<usize>().ok()?;
    let line_text = parts.next()?.to_owned();
    let column = workspace_search_grep_column(&line_text, query);
    Some((relative_path, line_number, column, line_text))
}

fn workspace_search_grep_column(line_text: &str, query: &str) -> usize {
    if query.is_empty() {
        return 1;
    }
    let case_sensitive = search_is_case_sensitive(query);
    if case_sensitive {
        return line_text.find(query).map(|offset| offset + 1).unwrap_or(1);
    }
    let line_lower = line_text.to_lowercase();
    let query_lower = query.to_lowercase();
    line_lower
        .find(&query_lower)
        .map(|offset| offset + 1)
        .unwrap_or(1)
}

fn workspace_search_match_entry(
    root: &Path,
    relative_path: &str,
    line_number: usize,
    byte_column: usize,
    line_text: &str,
) -> PickerEntry {
    let relative_path = relative_path
        .strip_prefix(".\\")
        .or_else(|| relative_path.strip_prefix("./"))
        .unwrap_or(relative_path);
    let path = root.join(relative_path);
    let column = workspace_search_char_column(line_text, byte_column.saturating_sub(1));
    let target = TextPoint::new(line_number.saturating_sub(1), column);
    let preview = line_text.trim();
    let label = if preview.is_empty() {
        format!("{relative_path}:{}", line_number)
    } else {
        preview.to_owned()
    };
    let detail = format!("{} | Ln {}, Col {}", relative_path, line_number, column + 1);
    PickerEntry {
        item: PickerItem::new(
            format!("{}:{}:{}", path.display(), line_number, column + 1),
            label,
            detail,
            Some(path.display().to_string()),
        ),
        action: PickerAction::OpenFileLocation { path, target },
    }
}

fn workspace_search_status_entry(
    query: &str,
    title: &str,
    detail: impl Into<String>,
    preview: Option<String>,
) -> PickerEntry {
    PickerEntry {
        item: PickerItem::new(
            format!("workspace-search:{query}"),
            format!("{title} for {query}"),
            detail,
            preview,
        ),
        action: PickerAction::NoOp,
    }
}

fn lsp_locations_picker_overlay(
    runtime: &EditorRuntime,
    title: &str,
    locations: &[LspLocation],
) -> PickerOverlay {
    let workspace_root = active_workspace_root(runtime).ok().flatten();
    let entries = locations
        .iter()
        .take(SEARCH_PICKER_ITEM_LIMIT)
        .map(|location| lsp_location_picker_entry(workspace_root.as_deref(), location))
        .collect();
    PickerOverlay::from_entries(title, entries)
}

fn lsp_location_picker_entry(workspace_root: Option<&Path>, location: &LspLocation) -> PickerEntry {
    let path = location.path().to_path_buf();
    let target = location.range().start();
    let relative_path = workspace_relative_path(workspace_root, &path);
    let line_number = target.line + 1;
    let column = target.column + 1;
    let preview = TextBuffer::load_from_path(&path)
        .ok()
        .and_then(|buffer| buffer.line(target.line))
        .map(|line| line.trim().to_owned())
        .filter(|line| !line.is_empty());
    let label = preview
        .clone()
        .unwrap_or_else(|| format!("{relative_path}:{line_number}"));
    let detail = format!(
        "{relative_path} | Ln {line_number}, Col {column} | {}",
        location.server_id()
    );
    PickerEntry {
        item: PickerItem::new(
            format!("lsp:{}:{}:{}", path.display(), line_number, column),
            label,
            detail,
            Some(path.display().to_string()),
        ),
        action: PickerAction::OpenFileLocation { path, target },
    }
}

fn lsp_code_actions_picker_overlay(
    workspace_id: WorkspaceId,
    buffer_id: BufferId,
    path: &Path,
    code_actions: &[LspCodeAction],
) -> PickerOverlay {
    let entries = code_actions
        .iter()
        .take(SEARCH_PICKER_ITEM_LIMIT)
        .enumerate()
        .map(|(index, code_action)| {
            lsp_code_action_picker_entry(workspace_id, buffer_id, path, index, code_action)
        })
        .collect();
    PickerOverlay::from_entries("Code Actions", entries)
}

fn lsp_code_action_picker_entry(
    workspace_id: WorkspaceId,
    buffer_id: BufferId,
    path: &Path,
    index: usize,
    code_action: &LspCodeAction,
) -> PickerEntry {
    let status = if code_action.disabled_reason().is_some() {
        "disabled"
    } else if lsp_code_action_supported_edits(code_action, path).is_ok() {
        "edit"
    } else {
        "unsupported"
    };
    let mut detail_parts = vec![code_action.server_id().to_owned()];
    if let Some(kind) = code_action.kind() {
        detail_parts.push(kind.to_owned());
    }
    if code_action.is_preferred() {
        detail_parts.push("preferred".to_owned());
    }
    detail_parts.push(status.to_owned());
    PickerEntry {
        item: PickerItem::new(
            format!("lsp-code-action:{index}"),
            code_action.title(),
            detail_parts.join(" | "),
            lsp_code_action_picker_preview(code_action, path),
        ),
        action: PickerAction::ApplyLspCodeAction {
            workspace_id,
            buffer_id,
            path: path.to_path_buf(),
            code_action: code_action.clone(),
        },
    }
}

fn lsp_code_action_picker_preview(code_action: &LspCodeAction, path: &Path) -> Option<String> {
    match lsp_code_action_supported_edits(code_action, path) {
        Ok(edits) => {
            let suffix = if edits.len() == 1 { "" } else { "s" };
            Some(format!(
                "Apply {} text edit{suffix} to the active file.",
                edits.len()
            ))
        }
        Err(message) => Some(message),
    }
}

fn lsp_code_action_supported_edits<'a>(
    code_action: &'a LspCodeAction,
    path: &Path,
) -> Result<&'a [LspTextEdit], String> {
    if let Some(reason) = code_action.disabled_reason() {
        return Err(format!("Disabled: {reason}"));
    }
    if code_action.has_resource_operations() {
        return Err("Unsupported: resource operations are not supported yet.".to_owned());
    }
    if let Some(command_name) = code_action.command_name() {
        return Err(format!(
            "Unsupported: command `{command_name}` code actions are not supported yet."
        ));
    }
    if code_action.document_edits().is_empty() {
        return Err("Unsupported: this code action does not include text edits.".to_owned());
    }
    if code_action.document_edits().len() != 1 {
        return Err("Unsupported: multi-file code actions are not supported yet.".to_owned());
    }
    let document_edit = &code_action.document_edits()[0];
    if document_edit.path() != path {
        return Err(format!(
            "Unsupported: this code action edits `{}` instead of the active file.",
            document_edit.path().display()
        ));
    }
    Ok(document_edit.edits())
}

fn apply_lsp_code_action(
    runtime: &mut EditorRuntime,
    workspace_id: WorkspaceId,
    buffer_id: BufferId,
    path: &Path,
    code_action: &LspCodeAction,
) -> Result<(), String> {
    let edits = lsp_code_action_supported_edits(code_action, path)?;
    let original_cursor = shell_buffer(runtime, buffer_id)?.cursor_point();
    {
        let buffer = shell_buffer_mut(runtime, buffer_id)?;
        if buffer.path() != Some(path) {
            return Err(format!(
                "buffer `{}` is no longer available for `{}`",
                path.display(),
                code_action.title()
            ));
        }
        apply_lsp_text_edits(buffer, edits);
        buffer.set_cursor(original_cursor);
    }
    runtime
        .model_mut()
        .focus_buffer(workspace_id, buffer_id)
        .map_err(|error| error.to_string())?;
    shell_ui_mut(runtime)?.focus_buffer(buffer_id);
    sync_active_buffer(runtime)?;
    Ok(())
}

fn workspace_search_char_column(line: &str, byte_offset: usize) -> usize {
    let mut byte_offset = byte_offset.min(line.len());
    while byte_offset > 0 && !line.is_char_boundary(byte_offset) {
        byte_offset = byte_offset.saturating_sub(1);
    }
    line[..byte_offset].chars().count()
}

fn git_command_output(
    runtime: &mut EditorRuntime,
    root: &Path,
    label: &str,
    args: &[&str],
) -> Result<String, String> {
    let spec = JobSpec::command(
        label,
        "git",
        args.iter().map(|arg| (*arg).to_owned()).collect::<Vec<_>>(),
    )
    .with_cwd(root.to_path_buf());
    let manager = runtime
        .services()
        .get::<Mutex<JobManager>>()
        .ok_or_else(|| "job manager service missing".to_owned())?;
    let mut manager = manager
        .lock()
        .map_err(|_| "job manager lock poisoned".to_owned())?;
    let handle = manager.spawn(spec).map_err(|error| error.to_string())?;
    drop(manager);
    let result = handle.wait().map_err(|error| error.to_string())?;
    if !result.succeeded() {
        return Err(format!("git {label} failed: {}", result.transcript()));
    }
    Ok(result.stdout().to_owned())
}

fn git_command_output_owned(
    runtime: &mut EditorRuntime,
    root: &Path,
    label: &str,
    args: &[String],
) -> Result<String, String> {
    let refs = args.iter().map(String::as_str).collect::<Vec<_>>();
    git_command_output(runtime, root, label, &refs)
}

fn git_command_output_allow_exit_codes(
    runtime: &mut EditorRuntime,
    root: &Path,
    label: &str,
    args: &[&str],
    allowed_exit_codes: &[i32],
) -> Result<String, String> {
    let spec = JobSpec::command(
        label,
        "git",
        args.iter().map(|arg| (*arg).to_owned()).collect::<Vec<_>>(),
    )
    .with_cwd(root.to_path_buf());
    let manager = runtime
        .services()
        .get::<Mutex<JobManager>>()
        .ok_or_else(|| "job manager service missing".to_owned())?;
    let mut manager = manager
        .lock()
        .map_err(|_| "job manager lock poisoned".to_owned())?;
    let handle = manager.spawn(spec).map_err(|error| error.to_string())?;
    drop(manager);
    let result = handle.wait().map_err(|error| error.to_string())?;
    let exit_code = result.exit_code().ok_or_else(|| {
        format!(
            "git {label} failed to return an exit code: {}",
            result.transcript()
        )
    })?;
    if exit_code != 0 && !allowed_exit_codes.contains(&exit_code) {
        return Err(format!("git {label} failed: {}", result.transcript()));
    }
    Ok(result.stdout().to_owned())
}

fn git_command_output_optional(
    runtime: &mut EditorRuntime,
    root: &Path,
    label: &str,
    args: &[&str],
) -> Option<String> {
    git_command_output(runtime, root, label, args).ok()
}

fn git_dir_path(runtime: &mut EditorRuntime, root: &Path) -> Option<PathBuf> {
    let output = git_command_output_optional(
        runtime,
        root,
        "rev-parse --git-dir",
        &["rev-parse", "--git-dir"],
    )?;
    let trimmed = output.trim();
    if trimmed.is_empty() {
        return None;
    }
    let path = PathBuf::from(trimmed);
    if path.is_absolute() {
        Some(path)
    } else {
        Some(root.join(path))
    }
}

fn git_status_snapshot(
    runtime: &mut EditorRuntime,
    root: &Path,
) -> Result<GitStatusSnapshot, String> {
    let status_output = git_command_output(
        runtime,
        root,
        "status --short --branch",
        &["status", "--short", "--branch"],
    )?;
    let status = parse_status(&status_output).map_err(|error| error.to_string())?;

    let head_output = git_command_output(
        runtime,
        root,
        "log -1 --oneline",
        &["log", "-1", "--oneline"],
    )?;
    let head = parse_log_oneline(&head_output).into_iter().next();

    let upstream = git_command_output_optional(
        runtime,
        root,
        "rev-parse --abbrev-ref @{upstream}",
        &["rev-parse", "--abbrev-ref", "@{upstream}"],
    )
    .map(|value| value.trim().to_owned())
    .filter(|value| !value.is_empty());
    let push_remote = git_command_output_optional(
        runtime,
        root,
        "rev-parse --abbrev-ref @{push}",
        &["rev-parse", "--abbrev-ref", "@{push}"],
    )
    .map(|value| value.trim().to_owned())
    .filter(|value| !value.is_empty());

    let stash_output = git_command_output_optional(runtime, root, "stash list", &["stash", "list"])
        .unwrap_or_default();
    let stashes = parse_stash_list(&stash_output);

    let unpulled = if upstream.is_some() {
        let output = git_command_output(
            runtime,
            root,
            "log --oneline ..@{upstream}",
            &["log", "--oneline", "..@{upstream}"],
        )?;
        parse_log_oneline(&output)
    } else {
        Vec::new()
    };
    let unpushed = if upstream.is_some() {
        let output = git_command_output(
            runtime,
            root,
            "log --oneline @{upstream}..",
            &["log", "--oneline", "@{upstream}.."],
        )?;
        parse_log_oneline(&output)
    } else {
        Vec::new()
    };
    let recent_output = git_command_output(
        runtime,
        root,
        "log --oneline",
        &["log", "-n", &GIT_LOG_LIMIT.to_string(), "--oneline"],
    )?;
    let recent = parse_log_oneline(&recent_output);

    let in_progress = git_dir_path(runtime, root)
        .map(detect_in_progress)
        .unwrap_or_default();

    Ok(GitStatusSnapshot::default()
        .with_status(status)
        .with_head(head)
        .with_upstreams(upstream, push_remote)
        .with_stashes(stashes)
        .with_unpulled(unpulled)
        .with_unpushed(unpushed)
        .with_recent(recent)
        .with_in_progress(in_progress))
}

fn git_remote_list(runtime: &mut EditorRuntime, root: &Path) -> Result<Vec<String>, String> {
    let output = git_command_output(runtime, root, "remote", &["remote"])?;
    let mut remotes = output
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .map(|line| line.to_owned())
        .collect::<Vec<_>>();
    remotes.sort();
    remotes.dedup();
    Ok(remotes)
}

fn keydown_chord(keycode: Keycode, keymod: Mod) -> Option<String> {
    if keymod.intersects(ctrl_mod()) {
        return match keycode {
            Keycode::Equals | Keycode::KpPlus => Some("Ctrl+=".to_owned()),
            Keycode::Minus | Keycode::KpMinus => Some("Ctrl+-".to_owned()),
            Keycode::_0 | Keycode::Kp0 => Some("Ctrl+0".to_owned()),
            Keycode::B => Some("Ctrl+b".to_owned()),
            Keycode::C => Some("Ctrl+c".to_owned()),
            Keycode::D => Some("Ctrl+d".to_owned()),
            Keycode::E => Some("Ctrl+e".to_owned()),
            Keycode::F => Some("Ctrl+f".to_owned()),
            Keycode::H => Some("Ctrl+h".to_owned()),
            Keycode::J => Some("Ctrl+j".to_owned()),
            Keycode::K => Some("Ctrl+k".to_owned()),
            Keycode::L => Some("Ctrl+l".to_owned()),
            Keycode::N => Some("Ctrl+n".to_owned()),
            Keycode::P => Some("Ctrl+p".to_owned()),
            Keycode::R => Some("Ctrl+r".to_owned()),
            Keycode::S => Some("Ctrl+s".to_owned()),
            Keycode::T => Some("Ctrl+t".to_owned()),
            Keycode::U => Some("Ctrl+u".to_owned()),
            Keycode::V => Some("Ctrl+v".to_owned()),
            Keycode::Y => Some("Ctrl+y".to_owned()),
            Keycode::Space => Some("Ctrl+Space".to_owned()),
            Keycode::Grave => Some("Ctrl+`".to_owned()),
            Keycode::Period | Keycode::KpPeriod => Some("Ctrl+.".to_owned()),
            Keycode::Return | Keycode::KpEnter => Some("Ctrl+Enter".to_owned()),
            Keycode::Tab => Some("Ctrl+Tab".to_owned()),
            _ => None,
        };
    }

    if keymod.intersects(alt_mod()) && !keymod.intersects(ctrl_mod() | gui_mod()) {
        return match keycode {
            Keycode::X => Some("Alt+x".to_owned()),
            _ => None,
        };
    }

    if keymod.intersects(shift_mod()) && matches!(keycode, Keycode::Tab) {
        return Some("Shift+Tab".to_owned());
    }

    match keycode {
        Keycode::F3 => Some("F3".to_owned()),
        Keycode::F4 => Some("F4".to_owned()),
        Keycode::F5 => Some("F5".to_owned()),
        Keycode::F6 => Some("F6".to_owned()),
        Keycode::Tab => Some("Tab".to_owned()),
        Keycode::Escape => Some("Escape".to_owned()),
        Keycode::Return | Keycode::KpEnter => Some("Enter".to_owned()),
        _ => None,
    }
}

fn text_chord(text: &str) -> Option<String> {
    let mut characters = text.chars();
    let character = characters.next()?;
    if characters.next().is_some() {
        return None;
    }
    Some(character.to_string())
}

fn normalize_text_token(chord: &str) -> String {
    if chord == " " {
        "Space".to_owned()
    } else {
        chord.to_owned()
    }
}

fn ctrl_mod() -> Mod {
    Mod::LCTRLMOD | Mod::RCTRLMOD
}

fn shift_mod() -> Mod {
    Mod::LSHIFTMOD | Mod::RSHIFTMOD
}

fn alt_mod() -> Mod {
    Mod::LALTMOD | Mod::RALTMOD
}

fn gui_mod() -> Mod {
    Mod::LGUIMOD | Mod::RGUIMOD
}

fn browser_devtools_shortcut_requested(keycode: Keycode, keymod: Mod) -> bool {
    if !keymod.intersects(alt_mod() | gui_mod()) && keycode == Keycode::F12 {
        return true;
    }
    keycode == Keycode::I
        && keymod.intersects(ctrl_mod())
        && keymod.intersects(shift_mod())
        && !keymod.intersects(alt_mod() | gui_mod())
}

fn terminal_key_for_event(keycode: Keycode, keymod: Mod) -> Option<TerminalKey> {
    if keymod.intersects(ctrl_mod()) && keycode == Keycode::C {
        return Some(TerminalKey::CtrlC);
    }
    match keycode {
        Keycode::Return | Keycode::KpEnter => Some(TerminalKey::Enter),
        Keycode::Backspace => Some(TerminalKey::Backspace),
        Keycode::Delete => Some(TerminalKey::Delete),
        Keycode::Left => Some(TerminalKey::Left),
        Keycode::Right => Some(TerminalKey::Right),
        Keycode::Up => Some(TerminalKey::Up),
        Keycode::Down => Some(TerminalKey::Down),
        Keycode::Home => Some(TerminalKey::Home),
        Keycode::End => Some(TerminalKey::End),
        Keycode::PageUp => Some(TerminalKey::PageUp),
        Keycode::PageDown => Some(TerminalKey::PageDown),
        Keycode::Tab if keymod.intersects(shift_mod()) => Some(TerminalKey::BackTab),
        Keycode::Tab => Some(TerminalKey::Tab),
        _ => None,
    }
}

fn keymap_vim_mode(input_mode: InputMode) -> KeymapVimMode {
    match input_mode {
        InputMode::Normal => KeymapVimMode::Normal,
        InputMode::Insert | InputMode::Replace => KeymapVimMode::Insert,
        InputMode::Visual => KeymapVimMode::Visual,
    }
}

fn plugin_vim_mode_matches(
    binding_mode: editor_plugin_api::PluginVimMode,
    active_mode: KeymapVimMode,
) -> bool {
    match binding_mode {
        editor_plugin_api::PluginVimMode::Any => true,
        editor_plugin_api::PluginVimMode::Normal => active_mode == KeymapVimMode::Normal,
        editor_plugin_api::PluginVimMode::Insert => active_mode == KeymapVimMode::Insert,
        editor_plugin_api::PluginVimMode::Visual => active_mode == KeymapVimMode::Visual,
    }
}

fn default_volt_state_dir() -> PathBuf {
    if cfg!(target_os = "windows") {
        let base = env::var_os("LOCALAPPDATA")
            .or_else(|| env::var_os("APPDATA"))
            .map(PathBuf::from)
            .unwrap_or_else(|| env::current_dir().unwrap_or_else(|_| PathBuf::from(".")));
        base.join("volt")
    } else {
        let base = env::var_os("XDG_STATE_HOME")
            .map(PathBuf::from)
            .or_else(|| {
                env::var_os("HOME").map(|home| PathBuf::from(home).join(".local").join("state"))
            })
            .unwrap_or_else(|| env::current_dir().unwrap_or_else(|_| PathBuf::from(".")));
        base.join("volt")
    }
}

fn default_error_log_path() -> PathBuf {
    default_volt_state_dir().join(ERROR_LOG_FILE_NAME)
}

fn active_theme_state_path() -> PathBuf {
    default_volt_state_dir().join(ACTIVE_THEME_STATE_FILE_NAME)
}

fn default_typing_profile_log_path() -> PathBuf {
    default_volt_state_dir().join(TYPING_PROFILE_LOG_FILE_NAME)
}

fn read_saved_theme_selection(path: &Path) -> Result<Option<String>, String> {
    match fs::read_to_string(path) {
        Ok(contents) => {
            let theme_id = contents.trim();
            if theme_id.is_empty() {
                Ok(None)
            } else {
                Ok(Some(theme_id.to_owned()))
            }
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(None),
        Err(error) => Err(format!(
            "failed to read saved theme from `{}`: {error}",
            path.display()
        )),
    }
}

fn write_saved_theme_selection(path: &Path, theme_id: &str) -> Result<(), String> {
    let Some(parent) = path.parent() else {
        return Err(format!(
            "saved theme path `{}` does not have a parent directory",
            path.display()
        ));
    };
    fs::create_dir_all(parent).map_err(|error| {
        format!(
            "failed to create theme state directory `{}`: {error}",
            parent.display()
        )
    })?;
    fs::write(path, format!("{theme_id}\n")).map_err(|error| {
        format!(
            "failed to write saved theme to `{}`: {error}",
            path.display()
        )
    })
}

fn clear_saved_theme_selection(path: &Path) -> Result<(), String> {
    match fs::remove_file(path) {
        Ok(()) => Ok(()),
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(()),
        Err(error) => Err(format!(
            "failed to clear saved theme `{}`: {error}",
            path.display()
        )),
    }
}

fn restore_saved_theme_selection(
    theme_registry: &mut ThemeRegistry,
    path: &Path,
) -> Result<(), String> {
    let Some(theme_id) = read_saved_theme_selection(path)? else {
        return Ok(());
    };
    if let Err(error) = theme_registry.activate(&theme_id) {
        clear_saved_theme_selection(path)?;
        return Err(format!(
            "saved theme `{theme_id}` is no longer available and was removed from `{}`: {error}",
            path.display()
        ));
    }
    Ok(())
}

fn ensure_log_directory(path: &Path) -> Result<(), String> {
    let Some(parent) = path.parent() else {
        return Ok(());
    };
    fs::create_dir_all(parent).map_err(|error| {
        format!(
            "failed to create log directory `{}`: {error}",
            parent.display()
        )
    })
}

fn install_panic_hook(log_file_path: PathBuf) {
    let default_hook = std::panic::take_hook();
    std::panic::set_hook(Box::new(move |info| {
        let entry = ErrorEntry::new(ErrorSeverity::Error, "panic", info.to_string());
        if let Err(error) = append_error_log(&log_file_path, &entry) {
            eprintln!("Failed to write panic log: {error}");
        }
        default_hook(info);
    }));
}

fn panic_payload_message(payload: Box<dyn Any + Send>) -> String {
    if let Some(message) = payload.downcast_ref::<&str>() {
        (*message).to_owned()
    } else if let Some(message) = payload.downcast_ref::<String>() {
        message.clone()
    } else {
        "panic payload is not a string".to_owned()
    }
}

fn format_timestamp(timestamp: SystemTime) -> String {
    match timestamp.duration_since(UNIX_EPOCH) {
        Ok(duration) => format!("{}.{:03}", duration.as_secs(), duration.subsec_millis()),
        Err(_) => "0.000".to_owned(),
    }
}

fn format_duration_ms(duration: Duration) -> String {
    let micros = duration.as_micros();
    format!("{}.{:03}ms", micros / 1_000, micros % 1_000)
}

fn average_duration(durations: &[Duration]) -> Duration {
    if durations.is_empty() {
        return Duration::from_secs(0);
    }
    let total_micros = durations
        .iter()
        .map(|duration| duration.as_micros())
        .sum::<u128>();
    let average_micros = total_micros / durations.len() as u128;
    let seconds = average_micros / 1_000_000;
    let nanos = ((average_micros % 1_000_000) * 1_000) as u32;
    Duration::new(seconds.min(u64::MAX as u128) as u64, nanos)
}

fn percentile_duration(durations: &[Duration], percentile: usize) -> Duration {
    if durations.is_empty() {
        return Duration::from_secs(0);
    }
    let mut sorted = durations.to_vec();
    sorted.sort();
    let clamped = percentile.min(100);
    let index = ((sorted.len().saturating_sub(1)) * clamped) / 100;
    sorted[index]
}

fn format_typing_frame_profile(frame: &TypingFrameProfile) -> String {
    let timestamp = format_timestamp(frame.timestamp);
    let preview = if frame.text_preview.is_empty() {
        "<none>".to_owned()
    } else {
        frame.text_preview.clone()
    };
    let first_to_present = frame
        .first_text_to_present
        .map(format_duration_ms)
        .unwrap_or_else(|| "-".to_owned());
    let last_to_present = frame
        .last_text_to_present
        .map(format_duration_ms)
        .unwrap_or_else(|| "-".to_owned());
    format!(
        "[{timestamp}] frame={} pacing_sleep={} events={} keydowns={} text_inputs={} preview=\"{}\" handle={} keydown_handle={} text_handle={} text_inner={} picker={} syntax_apply={} syntax_worker={} syntax_results={} syntax_spans={} git={} acp={} render={} present={} total={} first_text_to_present={} last_text_to_present={}",
        frame.frame_index,
        format_duration_ms(frame.frame_pacing_sleep),
        frame.polled_events,
        frame.keydown_events,
        frame.text_input_events,
        preview,
        format_duration_ms(frame.handle_event_total),
        format_duration_ms(frame.keydown_handle_total),
        format_duration_ms(frame.text_input_handle_total),
        format_duration_ms(frame.text_input_inner_total),
        format_duration_ms(frame.picker_refresh),
        format_duration_ms(frame.syntax_refresh),
        format_duration_ms(frame.syntax_worker_compute),
        frame.syntax_result_count,
        frame.syntax_highlight_spans,
        format_duration_ms(frame.git_refresh),
        format_duration_ms(frame.acp_refresh),
        format_duration_ms(frame.render),
        format_duration_ms(frame.present),
        format_duration_ms(frame.frame_total),
        first_to_present,
        last_to_present,
    )
}

fn sanitize_typing_preview(text: &str) -> String {
    let mut sanitized = String::new();
    for character in text.chars() {
        match character {
            '\n' => sanitized.push_str("\\n"),
            '\r' => sanitized.push_str("\\r"),
            '\t' => sanitized.push_str("\\t"),
            other => sanitized.push(other),
        }
    }
    sanitized
}

fn format_error_entry_lines(entry: &ErrorEntry) -> Vec<String> {
    let timestamp = format_timestamp(entry.timestamp);
    let mut lines = Vec::new();
    let mut message_lines = entry.message.lines();
    if let Some(first) = message_lines.next() {
        lines.push(format!(
            "[{timestamp}] {} {}: {first}",
            entry.severity.label(),
            entry.source
        ));
        for line in message_lines {
            lines.push(format!("    {line}"));
        }
    } else {
        lines.push(format!(
            "[{timestamp}] {} {}: <empty>",
            entry.severity.label(),
            entry.source
        ));
    }
    lines
}

fn append_error_log(path: &Path, entry: &ErrorEntry) -> Result<(), String> {
    let mut file = fs::OpenOptions::new()
        .create(true)
        .append(true)
        .open(path)
        .map_err(|error| format!("failed to open log `{}`: {error}", path.display()))?;
    for line in format_error_entry_lines(entry) {
        writeln!(file, "{line}")
            .map_err(|error| format!("failed to write log `{}`: {error}", path.display()))?;
    }
    Ok(())
}

fn errors_buffer_lines(entries: &[ErrorEntry], log_path: &Path) -> Vec<String> {
    let mut lines = initial_errors_lines(Some(log_path));
    if entries.is_empty() {
        return lines;
    }
    lines.push(String::new());
    lines.push(format!("Recent errors ({})", entries.len()));
    for entry in entries {
        lines.extend(format_error_entry_lines(entry));
    }
    lines
}

fn record_runtime_error(runtime: &mut EditorRuntime, source: &str, message: impl Into<String>) {
    let entry = ErrorEntry::new(ErrorSeverity::Error, source, message);
    let (buffer_id, lines) = {
        let Some(log) = runtime.services_mut().get_mut::<ErrorLog>() else {
            eprintln!("Error log service missing for: {}.", entry.message);
            return;
        };
        let lines = log.record(entry);
        (log.buffer_id, lines)
    };
    if let Err(error) = update_error_buffer(runtime, buffer_id, lines) {
        eprintln!("Failed to update errors buffer: {error}");
    }
}

fn update_error_buffer(
    runtime: &mut EditorRuntime,
    buffer_id: BufferId,
    lines: Vec<String>,
) -> Result<(), String> {
    let user_library = shell_user_library(runtime);
    let ui = shell_ui_mut(runtime)?;
    let buffer = ui.ensure_buffer(
        buffer_id,
        "*errors*",
        BufferKind::Diagnostics,
        &*user_library,
    );
    buffer.replace_with_lines(lines);
    Ok(())
}

fn format_lsp_log_entry_lines(entry: &LspLogEntry) -> Vec<String> {
    let timestamp = format_timestamp(entry.timestamp());
    let mut body_lines = entry
        .body()
        .lines()
        .map(str::trim_end)
        .map(str::to_owned)
        .collect::<Vec<_>>();
    let prefix = format!(
        "[{timestamp}] {} {}",
        entry.direction().label(),
        entry.server_id()
    );
    let mut lines = Vec::with_capacity(body_lines.len().saturating_add(2));
    if let Some(first) = body_lines.first() {
        lines.push(format!("{prefix}: {first}"));
        for line in body_lines.drain(1..) {
            lines.push(format!("    {line}"));
        }
    } else {
        lines.push(format!("{prefix}: <empty>"));
    }
    lines.push(String::new());
    lines
}

fn lsp_log_entries_for_server(entries: &[LspLogEntry], server_id: &str) -> Vec<LspLogEntry> {
    entries
        .iter()
        .filter(|entry| entry.server_id() == server_id)
        .cloned()
        .collect()
}

fn lsp_log_buffer_lines(server_id: &str, entries: &[LspLogEntry]) -> Vec<String> {
    let mut lines = initial_lsp_log_lines(server_id);
    if entries.is_empty() {
        return lines;
    }
    lines.push(String::new());
    lines.push(format!("Recent transport entries ({})", entries.len()));
    for entry in entries {
        lines.extend(format_lsp_log_entry_lines(entry));
    }
    lines
}

fn build_shell_summary(
    state: &mut ShellState,
    frames_rendered: u32,
    renderer_name: String,
    font_path: &Path,
) -> ShellSummary {
    let typing_profile = match state.finish_typing_profile() {
        Ok(profile) => profile,
        Err(error) => {
            state.record_error("typing-profile", error);
            None
        }
    };
    let pane_count = match state.pane_count() {
        Ok(count) => count,
        Err(error) => {
            state.record_shell_error("shell.summary.pane-count", error);
            0
        }
    };
    let popup_visible = match state.popup_visible() {
        Ok(visible) => visible,
        Err(error) => {
            state.record_shell_error("shell.summary.popup-visible", error);
            false
        }
    };
    ShellSummary {
        frames_rendered,
        pane_count,
        popup_visible,
        render_backend: RenderBackend::SdlCanvas,
        renderer_name,
        font_path: font_path.display().to_string(),
        typing_profile,
    }
}

